// Setup: read env vars + merge with webhook input
const body = $input.first().json.body || $input.first().json;

const tenantId = $env.MS_GRAPH_TENANT_ID;
const clientId = $env.MS_GRAPH_CLIENT_ID;
const clientSecret = $env.MS_GRAPH_CLIENT_SECRET;
const driveId = $env.SHAREPOINT_DRIVE_ID;
const proposalsFolderId = $env.OB_SHAREPOINT_PROPOSALS_FOLDER_ID;
const leadsTrackerFileId = $env.OB_LEADS_TRACKER_FILE_ID;
const kbFileId = $env.OB_SHAREPOINT_KB_FILE_ID;
const aoaiEndpoint = $env.AZURE_OPENAI_ENDPOINT;
const aoaiDeployment = $env.AZURE_OPENAI_CHAT_DEPLOYMENT;
const aoaiApiVersion = $env.AZURE_OPENAI_API_VERSION;
const mailUserUpn = $env.MAIL_USER_UPN;

return [{
  json: {
    tenantId, clientId, clientSecret, driveId,
    proposalsFolderId, leadsTrackerFileId, kbFileId,
    aoaiEndpoint, aoaiDeployment, aoaiApiVersion,
    mailUserUpn,
    lead: {
      leadId: body.leadId || `OB-LEAD-${Date.now()}`,
      fullName: body.fullName || '',
      email: body.email || '',
      company: body.company || '',
      industry: body.industry || '',
      problemDescription: body.problemDescription || '',
      serviceTier: body.serviceTier || body.suggestedTier || 'Professional',
      qualificationNotes: body.qualificationNotes || '',
      source: body.source || 'Website'
    }
  }
}];

// Save the access token and pass through setup vars, then prepare KB download URL
const setup = $('Setup Variables').first().json;
const tokenResp = $input.first().json;
const accessToken = tokenResp.access_token;
const driveId = setup.driveId;
const kbFileId = setup.kbFileId;

// Build the Graph API URL to download KB file content
const kbDownloadUrl = `https://graph.microsoft.com/v1.0/drives/${driveId}/items/${kbFileId}/content`;

return [{
  json: {
    ...setup,
    accessToken,
    kbDownloadUrl
  }
}];

// Build AI proposal generation prompt — grounded in Knowledge Base
const setup = $('Prepare KB Download').first().json;
const kbContent = $input.first().json.data || $input.first().json;
const lead = setup.lead;

// The KB download returns the raw markdown text
let knowledgeBase = '';
if (typeof kbContent === 'string') {
  knowledgeBase = kbContent;
} else if (kbContent.data && typeof kbContent.data === 'string') {
  knowledgeBase = kbContent.data;
} else {
  // Fallback: stringify whatever we got
  knowledgeBase = JSON.stringify(kbContent);
}

const systemPrompt = `You are a professional proposal writer for OpsBlueprint, a workflow automation consulting firm. You write formal, detailed automation consulting proposals that are STRICTLY grounded in the company's official knowledge base.

=== KNOWLEDGE BASE (AUTHORITATIVE SOURCE) ===
${knowledgeBase}
=== END KNOWLEDGE BASE ===

CRITICAL RULES:
1. You must ONLY include services, tiers, pricing, and deliverables that appear in the Knowledge Base above.
2. Do NOT invent, fabricate, or hallucinate any services, features, or pricing not listed in the Knowledge Base.
3. Use the exact tier names, pricing ranges, and included deliverables from the Knowledge Base.
4. The engagement process steps must match the Knowledge Base exactly.
5. Payment terms, cancellation policy, and other terms must come directly from the Knowledge Base.
6. If the client requests something not in the Knowledge Base, note it as a \"custom requirement requiring consultation.\"
7. Proposal validity is 30 days as stated in the Knowledge Base.

Generate a complete automation consulting proposal based on the lead information provided. The proposal should be professional, detailed, and tailored to their industry and pain points.

Return a JSON object with this exact structure:
{
  "companyName": "<client company>",
  "contactName": "<lead name>",
  "proposalDate": "<today's date>",
  "validUntil": "<30 days from today>",
  "executiveSummary": "<2-3 paragraph summary of their automation needs and our proposed solution>",
  "recommendedTier": "<Starter|Professional|Enterprise>",
  "estimatedInvestment": "<price range from KB>",
  "scopeOfWork": [
    {"phase": "<phase name>", "description": "<what we'll do>", "duration": "<timeline>"}
  ],
  "deliverables": ["<list of specific deliverables>"],
  "automationOpportunities": [
    {"process": "<manual process identified>", "solution": "<proposed automation>", "estimatedROI": "<time/cost savings>"}
  ],
  "timeline": "<overall project timeline>",
  "paymentTerms": "<from KB>",
  "nextSteps": ["<action items>"],
  "terms": "<key terms from KB>"
}`;

const userPrompt = `Generate an automation consulting proposal for this lead:

Name: ${lead.fullName}
Email: ${lead.email}
Company: ${lead.company}
Industry: ${lead.industry}
Problem: ${lead.problemDescription}
Service Tier Interest: ${lead.serviceTier}
Qualification Notes: ${lead.qualificationNotes}
Source: ${lead.source}`;

return [{
  json: {
    ...setup,
    lead,
    aoaiBody: {
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      max_completion_tokens: 4096,
      response_format: { type: 'json_object' }
    }
  }
}];

// Parse AI response and prepare data for DOCX generation
const prev = $('Build AI Proposal Prompt').first().json;
const aiResp = $input.first().json;
const lead = prev.lead;

let proposal;
try {
  proposal = JSON.parse(aiResp.choices[0].message.content);
} catch (e) {
  throw new Error(`Failed to parse AI proposal: ${e.message}`);
}

const safeName = (lead.fullName || 'Client').replace(/[^a-zA-Z0-9]/g, '_');
const filename = `OpsBlueprint_Proposal_${safeName}_${new Date().toISOString().split('T')[0]}.docx`;

return [{
  json: {
    accessToken: prev.accessToken,
    driveId: prev.driveId,
    proposalsFolderId: prev.proposalsFolderId,
    leadsTrackerFileId: prev.leadsTrackerFileId,
    lead,
    proposal,
    filename,
    leadId: lead.leadId
  }
}];

// Prepare internal notification email with DOCX attachment via MS Graph
const uploadResp = $input.first().json;
const prev = $('Prepare Proposal Data').first().json;
const setup = $('Setup Variables').first().json;
const lead = prev.lead;
const filename = uploadResp.filename || prev.filename;
const sharePointUrl = uploadResp.sharePointUrl || '';
const base64Content = uploadResp.base64Content || '';

const emailBody = `<h2>New OpsBlueprint Proposal Generated</h2>
<table style="border-collapse:collapse;width:100%">
<tr><td style="padding:6px;border:1px solid #ddd;font-weight:bold">Lead</td><td style="padding:6px;border:1px solid #ddd">${lead.fullName}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd;font-weight:bold">Company</td><td style="padding:6px;border:1px solid #ddd">${lead.company || 'N/A'}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd;font-weight:bold">Email</td><td style="padding:6px;border:1px solid #ddd">${lead.email}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd;font-weight:bold">Industry</td><td style="padding:6px;border:1px solid #ddd">${lead.industry || 'N/A'}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd;font-weight:bold">Service Tier</td><td style="padding:6px;border:1px solid #ddd">${lead.serviceTier || 'N/A'}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd;font-weight:bold">File</td><td style="padding:6px;border:1px solid #ddd">${filename}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd;font-weight:bold">SharePoint</td><td style="padding:6px;border:1px solid #ddd"><a href="${sharePointUrl}">${sharePointUrl ? 'View in SharePoint' : 'N/A'}</a></td></tr>
<tr><td style="padding:6px;border:1px solid #ddd;font-weight:bold">Size</td><td style="padding:6px;border:1px solid #ddd">${uploadResp.sizeBytes ? Math.round(uploadResp.sizeBytes / 1024) + ' KB' : 'N/A'}</td></tr>
</table>
<p style="margin-top:16px;color:#666">The proposal DOCX is attached to this email.</p>`;

const mailPayload = {
  message: {
    subject: `[OpsBlueprint] Proposal Generated — ${lead.fullName} (${lead.company || 'No Company'})`,
    body: { contentType: 'HTML', content: emailBody },
    toRecipients: [
      { emailAddress: { address: 'fxvarga@gmail.com' } },
      { emailAddress: { address: 'fernandovargas@busybee690.onmicrosoft.com' } }
    ],
    attachments: base64Content ? [{
      '@odata.type': '#microsoft.graph.fileAttachment',
      name: filename,
      contentType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      contentBytes: base64Content
    }] : []
  },
  saveToSentItems: true
};

return [{
  json: {
    accessToken: prev.accessToken || setup.accessToken || $('Prepare KB Download').first().json.accessToken,
    mailUserUpn: setup.mailUserUpn,
    mailPayload,
    // Pass through for Finalize
    uploadResp,
    lead,
    leadId: prev.leadId,
    filename,
    sharePointUrl
  }
}];

// Finalize: build webhook response from upload result
const prev = $('Prepare Notification').first().json;

return [{
  json: {
    status: 'proposal_generated',
    leadId: prev.leadId,
    filename: prev.filename,
    sharePointUrl: prev.sharePointUrl || '',
    docxSizeBytes: prev.uploadResp ? prev.uploadResp.sizeBytes || 0 : 0,
    generatedAt: new Date().toISOString(),
    notificationSent: true,
    message: 'Proposal generated, saved to SharePoint, and internal notification sent with attachment'
  }
}];
